// Sanitized operational-style event for Wd gate B live.
// See docs/runtime/test-events/wd-operational-decision-packet-test-event.json
const event = {
  event_id: 'D-1003-T',
  event_type: 'docs_change_candidate',
  summary: 'docs-only commit candidate requiring supervised Decision Packet test',
  touched_paths: ['docs/example.md'],
  source_repo: 'mrhz1973/control-plane',
  source_commit: 'abc1234-test-only',
  workflow_source: 'wd-operational-integration-test',
  runtime_flags: { touched: true, detail: 'runtime-adjacent Wd integration validation' },
  secrets_flags: { touched: false, detail: '' },
  deploy_flags: { touched: false, detail: '' },
  n8n_flags: { touched: false, workflow_40: false, workflow_41: false, import_disabled: false },
  automation_flags: { touched: false, autonomous_worker: false, commit_push_loop: false }
};
return [{ json: event }];

// Build operational-style Decision Packet from event + live classifier-server response.
// HTML parse_mode: escape dynamics; labels keep literal underscores.
function escHtml(v) {
  if (v === null || v === undefined) return '';
  const s = Array.isArray(v) ? v.map((x) => escHtml(x)).join('\n') : String(v);
  return s.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;').replace(/'/g, '&#39;');
}

const event = $('Set sanitized operational-style event').first().json;
const resp = $input.item.json;
const body = resp && resp.body !== undefined ? resp.body : resp;
const c = body && typeof body === 'object' ? body : {};

// D-0033 / Gate D fix:
// decision_id must follow the fresh event_id from the upstream sanitized event node.
// Do not hardcode D-1000-T.
const decisionId = event.event_id;

const options = [
  '1 — Record B live evidence only; no operational promotion',
  '2 — Harden Wd path (idempotency/guards) before further operational wiring',
  '3 — Stop; keep operational Decision Packet automation NOT RUN'
];

const optionsBlock = options.map((o) => '  ' + escHtml(o)).join('\n');
const context = 'Wd gate B: classifier-server response drives operational-style Decision Packet (TEST ONLY). PM-34 remains blocked; full automated chain NOT RUN.';
const why = 'Classifier route ' + escHtml(c.route || 'unknown') + ' with requires_human=' + escHtml(c.requires_human) + ' requires supervised Telegram gate for integration validation.';
const recommendation = 'Raccomandazione: 1 — record B live PASS/BLOCKED in docs only; do not enable operational automation.';
const mainRisk = 'Misreading TEST ONLY packet as operational approval; mitigated by banner and inactive workflow.';
const micro = 'Eliminates manual merge of classifier JSON and Decision Packet formatting in chat.';
const notDone = 'No PM-34 unlock, no operational automation, no full automated chain, no wf40/41 mutation, no Data Table write, no GitHub write by this workflow.';

const text = [
  '=== TEST ONLY / OPERATIONAL-STYLE VALIDATION ===',
  'No operational action should be taken from this test packet.',
  '',
  'ID: ' + escHtml(decisionId),
  'Kind: runtime',
  '',
  'Riferimento evento / provenienza:',
  '  event_id: ' + escHtml(event.event_id),
  '  commit: ' + escHtml(event.source_commit) + ' (' + escHtml(event.source_repo) + ')',
  '  source: ' + escHtml(event.workflow_source),
  '',
  'Risk: ' + escHtml(c.risk) + '          Route: ' + escHtml(c.route) + '       requires_human: ' + escHtml(c.requires_human),
  'Confidence: ' + escHtml(c.confidence) + '    Classifier reason: ' + escHtml(c.reason),
  '',
  'Contesto:',
  '  ' + escHtml(context),
  '',
  'Perché serve decisione:',
  '  ' + escHtml(why),
  '',
  'Opzioni:',
  optionsBlock,
  '',
  escHtml(recommendation),
  '',
  'Rischio principale (opzione raccomandata):',
  '  ' + escHtml(mainRisk),
  '',
  'Micro-interazioni eliminate:',
  '  ' + escHtml(micro),
  '',
  'Scelta richiesta:',
  '  Scrivi: 1 / 2 / 3',
  '',
  'Cosa NON viene fatto senza decisione:',
  '  ' + escHtml(notDone)
].join('\n');

return {
  json: {
    decision_id: decisionId,
    http_status: resp && resp.statusCode !== undefined ? resp.statusCode : null,
    classifier_output: c,
    decision_packet_text: text,
    test_only: true,
    operational_style_validation: true,
    note: 'Wd operational-style packet built — configure Telegram in n8n UI before send'
  }
};

// Read-only inspection — single audit item per run (fan-out collapsed).
// Works on sent (IF true -> Telegram) and blocked/no_send (IF false) branches.
const items = $input.all();
const build = $('Build Operational Decision Packet').first().json;
let prep = {};
try { prep = $('Prepare shared decision open row').first().json || {}; } catch (e) { prep = {}; }
const last = items.length ? items[items.length - 1].json : {};
const telegramRan = !!(last && (last.ok !== undefined || (last.result && last.result.message_id)));
const blocked = prep.open_allowed === false || prep.open_action === 'blocked';
const sendSuppressed = blocked || prep.open_action === 'blocked';
return [{
  json: {
    telegram_send_ok: telegramRan ? (last.ok !== undefined ? last.ok : null) : null,
    message_id: telegramRan && last.result && last.result.message_id ? last.result.message_id : null,
    http_status: build && build.http_status !== undefined ? build.http_status : null,
    decision_id: (build && build.decision_id) || prep.decision_id || null,
    open_action: prep.open_action !== undefined ? prep.open_action : null,
    block_reason: prep.block_reason !== undefined ? prep.block_reason : null,
    send_suppressed: sendSuppressed,
    fan_out_items_in: items.length,
    fan_out_collapsed: items.length > 1,
    pass_claimed: false,
    test_only: true,
    note: sendSuppressed
      ? 'Wd blocked terminal — no Telegram send; http_status is classifier-only not send PASS'
      : 'Wd gate B live result — sanitize before recording; no send claimed unless Telegram ran'
  }
}];

// Prepare OPEN ON SEND row for control_plane_decisions_test (TEST ONLY). No secrets.
// runOnceForAllItems: Load may return N store rows; logic uses .all() once — must emit 1 item.
const build = $('Build Operational Decision Packet').first().json;
let rows = [];
try { rows = $('Data Table - Load shared decisions').all().map((i) => i.json); } catch (e) { rows = []; }
const decision_id = build && build.decision_id ? build.decision_id : null;
const existing = rows.find((r) => r && String(r.decision_id) === String(decision_id));
const now = new Date().toISOString();
const SOURCE_WORKFLOW = '45 - Wd Operational Decision Packet Integration TEST ONLY - TEMPLATE';
let open_action = 'insert';
let block_reason = null;
let open_allowed = true;
if (existing) {
  if (String(existing.status) === 'closed') {
    open_action = 'blocked';
    block_reason = 'duplicate_open_attempt';
    open_allowed = false;
  } else if (String(existing.status) === 'open') {
    open_action = 'noop';
  } else {
    open_action = 'reopen_nonclosed';
  }
}
const row = {
  decision_id,
  status: 'open',
  selected_option: '',
  created_at: existing && existing.created_at ? existing.created_at : now,
  closed_at: '',
  update_id: '',
  note_preview: '',
  source: 'TEST ONLY',
  updated_at: now,
  created_by: 'wd',
  source_workflow: SOURCE_WORKFLOW,
  packet_kind: 'runtime'
};
return [{
  json: {
    decision_id,
    open_action,
    open_allowed,
    block_reason,
    row,
    decision_packet_text: build && build.decision_packet_text ? build.decision_packet_text : '',
    test_only: true
  }
}];

// Collapse Data Table load fan-out: Load returns 1 item per store row (returnAll).
// Downstream Prepare / IF / Telegram / Inspect must receive exactly 1 gate item per run.
const build = $('Build Operational Decision Packet').first().json;
const loaded = $input.all();
const rowCount = loaded.length;
return [{
  json: {
    decision_id: build && build.decision_id ? build.decision_id : null,
    store_rows_loaded: rowCount,
    fan_out_collapsed: rowCount > 1,
    test_only: true,
    note: 'Wd: collapsed load fan-out to single gate item before shared decision open prep'
  }
}];
